// components/QuestionItem.jsx — Single practice question with reveal
import React, { useState } from "react";

export default function QuestionItem({ question, index, showAnswer = false }) {
  const [revealed, setRevealed] = useState(showAnswer);
  const [selected, setSelected] = useState(null);

  const isCorrect = selected === question.answer;

  return (
    <div className="border-b border-border py-5 last:border-0">
      {/* Question text */}
      <p className="text-sm text-gray-200 mb-4 leading-relaxed">
        <span className="text-muted font-mono mr-2">Q{index + 1}.</span>
        {question.question}
      </p>

      {/* Options */}
      <div className="space-y-2 pl-5">
        {question.options.map((opt) => {
          const letter = opt.charAt(0); // "A", "B", "C", "D"
          const isAnswer = letter === question.answer;
          const isSelected = letter === selected;

          let optClass = "text-gray-400 hover:text-gray-200";
          if (revealed) {
            if (isAnswer) optClass = "text-green-400";
            else if (isSelected && !isAnswer) optClass = "text-red-400 line-through";
          } else if (isSelected) {
            optClass = "text-accent";
          }

          return (
            <button
              key={letter}
              onClick={() => {
                if (!revealed) {
                  setSelected(letter);
                  setRevealed(true);
                }
              }}
              className={`block text-left text-sm transition-colors duration-100 ${optClass}`}
            >
              {opt}
            </button>
          );
        })}
      </div>

      {/* Answer explanation */}
      {revealed && (
        <div className="mt-4 pl-5">
          <p className="text-xs font-mono text-muted mb-1">
            Answer:{" "}
            <span className="text-green-400 font-medium">{question.answer}</span>
          </p>
          {question.explanation && (
            <p className="text-xs text-gray-500 leading-relaxed">{question.explanation}</p>
          )}
        </div>
      )}

      {/* Manual reveal if no option selected yet */}
      {!revealed && selected === null && (
        <button
          onClick={() => setRevealed(true)}
          className="mt-3 pl-5 text-xs text-muted hover:text-gray-300 transition-colors"
        >
          Show answer
        </button>
      )}
    </div>
  );
}
